
import streamlit as st

st.title("Antifungal Pharmacokinetics Calculator")

st.image("https://static.scientificamerican.com/sciam/cache/file/BC2412FA-1388-43B7-877759A80E201C16_source.jpg?w=1200")

# -------------------------
# Drug Selection
# -------------------------
drug = st.selectbox("Select Drug 💊", [
    "Voriconazole",
    "Posaconazole",
    "Itraconazole",
    "Flucytosine"
])

if drug == "Voriconazole":
    st.image("data:image/jpeg;base64,")
elif drug == "Posaconazole":
    st.image("data:image/jpeg;base64,")
elif drug == "Itraconazole":
    st.image("data:image/jpeg;base64,")
elif drug == "Flucytosine":
    st.image("data:image/jpeg;base64,")
st.write("Enter patient data:")

# -------------------------
# Inputs
# -------------------------
weight = st.number_input("Weight (kg) ⚖️", min_value=0.0, value=None, placeholder="Enter weight")
if weight:
    height = st.number_input("Height (cm) 🧍‍♂️", min_value=0.0, value=None, placeholder="Enter height")
    if height:
        age = st.slider("Age 🩻", min_value=1, max_value=100)
        if age:
            if drug == "Flucytosine":
                dose = 25
            else:
                old_dose_statues = st.select_slider("Dose Status ⌛️", ["Loading" , "Maintenance"])
            css = st.number_input("Css (mg/L) ⚗️", min_value=0.0, value=None, placeholder="Enter Css")
            if css:
                gender = st.selectbox("Gender ☯️", ['male', 'female'])
                if gender:
                    scr = st.number_input("Scr (mg/dL)☢️", min_value=0.0, value=None, placeholder="Enter Scr")
                    if scr:
                        c_measured = st.number_input("C measured (mg/L)🌡", min_value=0.0, value=None, placeholder="Enter C_measured")
                        if c_measured:  
                            if drug == "Voriconazole":
                                if old_dose_statues == "Loading":
                                    dose = 6
                                else:
                                    dose = 4
                                infusion_time = 2
                                tau = 12
                                vd_factor = st.selectbox("Vd (L/kg) 🧴", [4.0, 4.6, 5.0])
                                st.info(f"tau is fixed at 12 hour, Dose {dose} mg/kg, Infusion time 120 minutes")

                            elif drug == "Posaconazole":
                                dose = 300
                                infusion_time = 1.5
                                tau = 24
                                vd_factor = st.selectbox("Vd (L/kg)", [5.0, 7.5, 10.0])
                                st.info("tau is fixed at 24 hour, Dose 300 mg, Infusion time 90 minutes")

                            elif drug == "Itraconazole":
                                dose = 200
                                infusion_time = 1
                                tau = st.selectbox("tau", [12.0, 24.0])
                                vd_factor = 10.0
                                st.info("Vd is fixed at 10 L/kg, Dose 200 mg, Infusion time 60 minutes")

                            elif drug == "Flucytosine":
                                tau = 6
                                vd_factor = st.selectbox("Vd (L/kg)", [0.6, 0.75, 0.9])
                                st.info("tau is fixed at 6 hour , Dose 25 mg/kg")
                            
                            if st.button("Calculate"):

                                try:
                                    vd = weight * vd_factor

                                    # -------------------------
                                    # Common Calculations
                                    # -------------------------
                                    
                                    if drug == "Voriconazole":
                                        clcr = ((140 - age) * weight / (72 * scr)) * 0.85
                                        cl = 0.1 * weight
                                        t_half = (0.693 * vd) / cl
                                        ld = css * vd - 44
                                        md = cl * css * tau + 32
                                        infusion_rate = md / infusion_time
                                        new_dose = md * (css / c_measured)
                                        

                                    elif drug == "Posaconazole":
                                        clcr = ((140 - age) * weight / (72 * scr)) * 0.85
                                        cl = 0.04 * weight
                                        t_half = (0.693 * vd) / cl
                                        ld = css * vd 
                                        md = cl * css * tau 
                                        infusion_rate = dose / infusion_time
                                        new_dose = dose * (css / c_measured)

                                    elif drug == "Itraconazole":
                                        clcr = ((140 - age) * weight / (72 * scr)) * 0.85
                                        cl = 0.02 * weight
                                        t_half = 30
                                        ld = css * vd 
                                        md = dose 
                                        infusion_rate = dose / infusion_time
                                        new_dose = dose * (css / c_measured)

                                    elif drug == "Flucytosine":
                                        clcr = ((140 - age) * weight / (72 * scr)) * 0.85
                                        cl = clcr * 0.06
                                        t_half = (0.693 * vd) / cl
                                        ld = css * vd 
                                        md = cl * css * tau - 130
                                        infusion_rate = md - 0.5
                                        new_dose = md * (css / c_measured)
                                        
                                    
                                    
                                    
                                    # -------------------------
                                    # Results
                                    # -------------------------
                                    st.subheader("Results:")

                                    st.write(f"Volume of Distribution (Vd): {vd:.2f} L")
                                    st.write(f"Clearance (Cl): ~ {cl:.2f} L/hr")
                                    st.write(f" Old Dose (Ld): ~ {ld:.2f} mg")
                                    st.write(f"Maintenance Dose (Md): ~ {md:.2f} mg")
                                    st.write(f"New Dose (Mg/kg): ~ {new_dose:.2f}Mg")
                                    st.write(f"Clcr (mL/min): {clcr:.2f}mL/min")

                                    st.write(f"Half-life (t½): ~ {t_half}")
                                    st.write(f"Infusion Rate: ~ {infusion_rate:.2f} mg/hr")
                                    
                                    
                                    
                                    st.markdown("---")

                                    # -------------------------
                                    # Clinical Notes (From Document)
                                    # -------------------------
                                    st.subheader("Clinical Notes & Monitoring")
                                    
                                    if drug == "Voriconazole":
                                        st.info("Repeat a 2nd pre-dose 3-5 days after the first level and 3-5 days after any dose alteration or iv to oral switch.")
                                    
                                    elif drug == "Posaconazole":
                                        st.info("Repeat a pre-dose level 7 days after any dose change.")
                                    
                                    elif drug == "Itraconazole":
                                        st.info("Use oral solution in preference to capsules if possible (superior bioavailability).\n\nRepeat a pre-dose level 7 days after any dose change.")
                                    
                                    elif drug == "Flucytosine":
                                        st.error("⚠️ Levels greater than 100mg/L are toxic.")
                                        st.info("Repeat pre and post-dose levels within 3 days of any dose change.")

                                except ZeroDivisionError:
                                    st.error("Invalid input: division by zero")

